// src/components/AppointmentForm.js
import React, { useEffect, useState } from "react";
import * as api from "../utils/api";
import "./AppointmentForm.css";

const initialForm = {
  patientId: "",
  doctorId: "",
  appointmentDate: "",
  appointmentTime: "",
  reason: "",
};

export default function AppointmentForm() {
  const [form, setForm] = useState(initialForm);
  const [errors, setErrors] = useState({});
  const [successMessage, setSuccessMessage] = useState("");
  const [serverError, setServerError] = useState("");
  const [doctors, setDoctors] = useState([]);
  const [loadingDoctors, setLoadingDoctors] = useState(false);

  useEffect(() => {
    let mounted = true;
    setLoadingDoctors(true);
    setServerError("");
    api.fetchDoctors()
      .then((d) => {
        if (!mounted) return;
        setDoctors(Array.isArray(d) ? d : []);
      })
      .catch((err) => {
        console.error("fetchDoctors error:", err);
        if (mounted) {
          setDoctors([]);
          setServerError(
            err?.message || "Cannot load doctors. See console for details."
          );
        }
      })
      .finally(() => mounted && setLoadingDoctors(false));
    return () => { mounted = false; };
  }, []);

  const handleChange = (field) => (e) => {
    setForm({ ...form, [field]: e.target.value });
    setErrors((prev) => ({ ...prev, [field]: "" }));
    setSuccessMessage("");
    setServerError("");
  };

  const validate = () => {
    const e = {};
    if (!form.patientId) e.patientId = "Patient is required";
    if (!form.doctorId) e.doctorId = "Doctor is required";
    if (!form.appointmentDate) e.appointmentDate = "Appointment date is required";
    if (!form.appointmentTime) e.appointmentTime = "Appointment time is required";
    if (!form.reason || form.reason.trim().length < 10)
      e.reason = "Reason is required (at least 10 chars)";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = async () => {
    setSuccessMessage("");
    setServerError("");
    if (!validate()) return;

    // Helpful debug info
    console.debug("Booking payload:", form);

    try {
      // createAppointment is expected to throw an Error whose message is user-friendly
      await api.createAppointment({
        patientId: Number(form.patientId),
        doctorId: Number(form.doctorId),
        appointmentDate: form.appointmentDate,
        appointmentTime: form.appointmentTime,
        reason: form.reason.trim(),
      });

      setForm(initialForm);
      setErrors({});
      setSuccessMessage("Appointment successfully booked");
    } catch (err) {
      // err.message comes from api interceptor (useful)
      console.error("createAppointment error:", err);
      // Friendly message to user, but keep console error for debugging
      setServerError(
        err?.message ||
        "Network error — could not reach the server. Check backend and CORS."
      );
    }
  };

  return (
    <div className="appointment-card">
      <h2 className="appointment-title">Book Appointment</h2>
      <form className="appointment-form" onSubmit={(e) => { e.preventDefault(); handleSubmit(); }}>
        <div className="form-group">
          <label className="field-label">Patient</label>
          <input
            data-testid="patient-input"
            className="field-input"
            placeholder="Enter patient id (or register first)"
            value={form.patientId}
            onChange={handleChange("patientId")}
          />
          {errors.patientId && <div className="field-error">{errors.patientId}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">
            Doctor {loadingDoctors ? "(loading...)" : doctors.length ? "" : "(no doctors)"}
          </label>
          <select
            data-testid="doctor-select"
            className="field-input"
            value={form.doctorId}
            onChange={handleChange("doctorId")}
          >
            <option value="">Select doctor</option>
            {doctors.map((d) => (
              <option key={d.id} value={d.id}>
                {d.name} ({d.specialization})
              </option>
            ))}
          </select>
          {errors.doctorId && <div className="field-error">{errors.doctorId}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Appointment date</label>
          <input
            type="date"
            data-testid="date-input"
            className="field-input"
            value={form.appointmentDate}
            onChange={handleChange("appointmentDate")}
          />
          {errors.appointmentDate && <div className="field-error">{errors.appointmentDate}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Appointment time</label>
          <input
            type="time"
            data-testid="time-input"
            className="field-input"
            value={form.appointmentTime}
            onChange={handleChange("appointmentTime")}
          />
          {errors.appointmentTime && <div className="field-error">{errors.appointmentTime}</div>}
        </div>

        <div className="form-group">
          <label className="field-label">Reason for appointment</label>
          <textarea
            data-testid="reason-input"
            className="field-input textarea-field"
            value={form.reason}
            onChange={handleChange("reason")}
          />
          {errors.reason && <div className="field-error">{errors.reason}</div>}
        </div>

        {serverError && <div className="field-error" data-testid="server-error">{serverError}</div>}
        {successMessage && <div className="field-success" data-testid="success">{successMessage}</div>}

        <button type="submit" className="primary-btn">Book Appointment</button>
      </form>
    </div>
  );
}
